// Public-facing worker
addEventListener('fetch', event => {
  const url = new URL(event.request.url);

  // Forward user requests to internal workers
  const internalWorker = new Worker('internal-worker.js');
  internalWorker.postMessage({
    method: event.request.method,
    url: url.pathname,
    body: await event.request.text(),
  });

  // Listen for responses from internal workers
  internalWorker.addEventListener('message', e => {
    const response = new Response(e.data.body, {
      status: e.data.status,
      headers: e.data.headers,
    });
    event.respondWith(response);
  });
});

